const express = require('express');
const { Client } = require('@google-cloud/dialogflow/v2');
const axios = require('axios');

const app = express();
app.use(express.json());

// Create a client instance of the dialogflow library
const client = new Client({
    keyFilename: 'path_to_service_account_key_file',
});

// Route to accept user prompts and generate code
app.post('/generate-code', async (req, res) => {
    const prompt = req.body.prompt;
    if (!prompt) {
        return res.status(400).json({ error: 'No prompt provided' });
    }

    // Send prompt to LLM model for code generation
    try {
        const response = await axios.post('https://api.llm-service.com/generate-code', {
            prompt,
        });

        const generatedCode = response.data;

        // Execute the generated code using child process or other Node.js modules
        execGeneratedCode(generatedCode);
        res.json({ success: true });
    } catch (error) {
        console.error(error);
        res.status(500).json({ error: 'Failed to generate code' });
    }
});

// Function to execute the generated code using child_process module
function execGeneratedCode(code) {
    const childProcess = require('child_process');

    // Execute code in Node.js environment (e.g., in a temporary file)
    try {
        childProcess.execSync(`node -e "${code}"`);
    } catch (error) {
        console.error(error);
        process.exit(1); // Exit with non-zero status code
    }
}

// Start the server
const port = 3000;
app.listen(port, () => {
    console.log(`Server listening on port ${port}`);
});